        res.status(400).json({ message: err.message });
    }
};

const login = async (req, res) => {
    try {
        const { email, password } = req.body;
        const data = await authService.login({ email, password });
        res.json(data);
    } catch (err) {
        res.status(401).json({ message: err.message });
    }
};


