        data: {
            email,
            passwordHash,
            username,
            emailVerified: false,
            lastLoginAt: new Date()
        }
    });

    const accessToken = generateAccessToken(user.id);

    return {
        user: {
            id: user.id,
            email: user.email,
            username: user.username
        },
        accessToken
    };
}


